from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse

app = FastAPI()

class CustomError(Exception):
    def __init__(self, name: str, message: str):
        self.name = name
        self.message = message

@app.exception_handler(CustomError)
async def custom_error_handler(request: Request, exc: CustomError):
    return JSONResponse(
        status_code=400,
        content={
            "error_type": exc.name,
            "message": exc.message,
            "path": request.url.path
        },
    )

@app.get("/")
async def read_root():
    return {"message": "Welcome! Try /raise-error to see custom exception handler."}

@app.get("/raise-error")
async def raise_custom_error():
    raise CustomError(name="InvalidInput", message="The provided input was not valid.")

@app.get("/raise-another-error/{item_id}")
async def raise_another_custom_error(item_id: int):
    if item_id % 2 != 0:
        raise CustomError(name="OddItemIdError", message=f"Item ID {item_id} is odd, which is not allowed.")
    return {"message": f"Item ID {item_id} is even and valid."}
